   222→    /// <summary>
   223→    /// Edit a teamMember
   224→    /// </summary>
   225→    /// <param name="model"></param>
   226→    /// <returns></returns>
   227→    [HttpPost]
   228→    [ValidateAntiForgeryToken]
   229→    [MultipleButtonAction(Name = "action", Argument = "Edit")]
   230→    [Authorize(Roles = "BF Administrator,BF Manage User Password,BF User Manager (Training)")]
   231→    public ActionResult Edit(ApplicationUserModel model)
   232→    {
   233→      model.Roles = db.Roles.Select(x => new ApplicationRoleModel
   234→      {
   235→        Id = x.Id,
   236→        Name = x.Name
   237→      }).ToList();
   238→
   239→      if (ModelState.IsValid)
   240→      {
   241→        var user = userService.FindById(model.Id);
   242→
   243→        if (user == null)
   244→        {
   245→          this.NotifyError("User not found.");
   246→          return RedirectToAction("Index");
   247→        }
   248→
   249→        var oldRoles = userService.GetRoles(model.Id).ToArray();
   250→        var newRoles = model.SelectedRoleNames;
   251→
   252→        user.IsActive = model.IsActive;
   253→        user.UserName = user.UserName;
   254→        user.Email = model.Email;
   255→        user.EmailConfirmed = model.EmailConfirmed;
   256→        user.Description = model.Description;
   257→        user.PictureId = model.AvatarId;
   258→        user.Name = model.Name;
   259→        user.Surname = model.Surname;
   260→        user.Location = model.Location;
   261→        user.Badge = model.Badge;
   262→        user.NormalizedUserName = user.UserName;
   263→        user.ControlID = model.ControlID;
   264→        
   265→
   266→        if (Request.IsAuthenticated && (User.IsInRole("BF Administrator")))
   267→        {
   268→          newRoles = model.SelectedRoleNames;
   269→        }
   270→        else
   271→        {
   272→          newRoles = oldRoles;
   273→
   274→          user.IsActive = user.IsActive;
   275→          user.UserName = user.UserName;
   276→          user.Email = model.Email;
   277→          user.EmailConfirmed = model.EmailConfirmed;
   278→          user.Description = model.Description;
   279→          user.PictureId = model.AvatarId;
   280→          user.Name = user.Name;
   281→          user.Surname = user.Surname;
   282→          user.Location = user.Location;
   283→          user.Badge = model.Badge;
   284→          user.NormalizedUserName = user.UserName;
   285→          user.ControlID = model.ControlID;
   286→
   287→        }
   288→       
   289→
   290→        #region AddOrRemoveRoles
   291→        try
   292→        {
   293→          var rolesToRemove = oldRoles.Except(newRoles);
   294→          foreach (var role in rolesToRemove)
   295→            userService.RemoveFromRole(user.Id, role);
   296→
   297→          var rolesToAdd = newRoles.Except(oldRoles);
   298→          foreach (var role in rolesToAdd)
   299→            userService.AddToRole(user.Id, role);
   300→        }
   301→        catch
   302→        {
   303→
   304→        }
   305→        #endregion AddOrRemoveRoles
   306→
   307→        var result = userService.Update(user);
   308→        if (result.Succeeded)
   309→          this.NotifySuccess("Successfully saved.");
   310→        else
   311→          this.NotifyError("User can not saved!");
   312→
   313→        return RedirectToAction("Edit", new { id = model.Id });
   314→      }
   315→
   316→      return View(model);
   317→    }
