   322→    [Authorize(Roles = "BF User Add Image,BF User Manager (Training)")]
   323→    [HttpPost]
   324→    public ActionResult UploadFile()
   325→    {
   326→      string name = "";
   327→      // Checking no of files injected in Request object  
   328→
   329→      int test = Request.Files.Count;
   330→      if (Request.Files.Count > 0)
   331→      {
   332→        try
   333→        {
   334→          //  Get all files from Request object  
   335→          HttpPostedFileBase fileBase = Request.Files["file_name"];
   336→          HttpFileCollectionBase files = Request.Files;
   337→          string resultado = "";
   338→          for (int i = 0; i < files.Count; i++)
   339→          {
   340→            //string path = AppDomain.CurrentDomain.BaseDirectory + "Uploads/";
   341→            string filename = Path.GetFileName(Request.Files[i].FileName);
   342→            HttpPostedFileBase file = files[i];
   343→            string fname;
   344→            string fext;
   345→
   346→            // Checking for Internet Explorer  
   347→            if (Request.Browser.Browser.ToUpper() == "IE" || Request.Browser.Browser.ToUpper() == "INTERNETEXPLORER")
   348→            {
   349→              string[] testfiles = file.FileName.Split(new char[] { '\\' });
   350→              fname = testfiles[testfiles.Length - 1];
   351→            }
   352→            else
   353→            {
   354→              fname = file.FileName;
   355→            }
   356→            fext = Path.GetExtension(fname);
   357→
   358→
   359→            if (Firstronic.Framework.Upload.Upload.IsValidExtension(fext) && Firstronic.Framework.Upload.Upload.IsValidName(fname))
   360→            {
   361→
   362→              int id = 0;
   363→
   364→              try
   365→              {
   366→                id = Firstronic.Framework.Functions.Queries.GetNextIDFromQuery("Common_Files_Uploaded", "FileID");
   367→              }
   368→              catch (Exception ex)
   369→              {
   370→                ViewBag.Message = "ERROR:" + ex.Message.ToString();
   371→              }
   372→              name = id + "_" + 0 + fext;
   373→              SqlParameter[] parameters = new SqlParameter[]{
   374→                        new SqlParameter("@FileName",SqlDbType.NVarChar){Value = name},
   375→                        new SqlParameter("@Extension",SqlDbType.NVarChar){Value = fext},
   376→                };
   377→
   378→              //var result = db.ExecuteInsertCommand($@"", parameters);
   379→
   380→              var result_Update = db.ExecuteInsertCommand(@"INSERT INTO Common_Files_Uploaded  ([FileName],Extension) VALUES (@FileName,@Extension)", parameters);
   381→              // Get the complete folder path and store the file inside it.  
   382→              fname = Path.Combine(Server.MapPath("~/UploadedFiles/Users"), name);
   383→              file.SaveAs(fname);
   384→
   385→              resultado = name;
   386→
   387→
   388→            }
   389→
   390→          }
   391→          // Returns message that successfully uploaded  
   392→          return Json(resultado);
   393→        }
   394→        catch (Exception ex)
   395→        {
   396→          ViewBag.Message = "ERROR:" + ex.Message.ToString();
   397→          return Json("");
   398→        }
   399→      }
   400→      else
   401→      {
   402→        return Json("");
   403→      }
   404→    }
