    [Authorize]
    public ActionResult Edit(string id)
    {

      bool continuetopage = false;

      if (Request.IsAuthenticated && (User.IsInRole("BF Administrator") || User.IsInRole("BF User Manager (Training)")))
      {
        continuetopage = true;
      }
      else
      {
        if (Request.IsAuthenticated && User.IsInRole("BF Administrator") == false)
        {
          if (User.Identity.GetUserId() == id)
          {
            continuetopage = true;
          }
        }
      }

      if (continuetopage)
      {
        var user = userService.GetById(id);
        if (user == null)
        {
          this.NotifyError("User not found.");
          return RedirectToAction("Index");
        }

        var roles = db.Roles.Select(x => new ApplicationRoleModel
        {
          Id = x.Id,
          Name = x.Name
        }).OrderBy(x => x.Name).ToList();

        var model = new ApplicationUserModel
        {
          Id = user.Id,
          Name = user.Name,
          UserName = user.UserName,
          Email = user.Email,
          EmailConfirmed = user.EmailConfirmed,
          IsActive = user.IsActive,
          AvatarId = user.PictureId,
          Description = user.Description,
          Location = user.Location,
          Badge = user.Badge,
          Surname = user.Surname,
          Roles = roles,
          SelectedRoleNames = userService.GetRoles(user.Id).ToArray()
        };

        SqlParameter[] parameters = new SqlParameter[]{
          new SqlParameter("@Id",SqlDbType.NVarChar){Value = model.Id},
        };

        model.ControlID = Firstronic.Framework.Queries.GetIntFromQuery("Select ControlID from AspNetUsers WHERE ID=@Id", parameters);

        return View(model);
      }
      else
      {
        this.NotifyError("No allowed");
        return RedirectToAction("Index");
      }
    }

    /// <summary>
    /// Edit a teamMember
    /// </summary>
    /// <param name="model"></param>
    /// <returns></returns>
    [HttpPost]
    [ValidateAntiForgeryToken]
    [MultipleButtonAction(Name = "action", Argument = "Edit")]
    [Authorize(Roles = "BF Administrator,BF Manage User Password,BF User Manager (Training)")]
    public ActionResult Edit(ApplicationUserModel model)
    {
      model.Roles = db.Roles.Select(x => new ApplicationRoleModel
      {
        Id = x.Id,
        Name = x.Name
      }).ToList();

      if (ModelState.IsValid)
      {
        var user = userService.FindById(model.Id);

        if (user == null)
        {
          this.NotifyError("User not found.");
          return RedirectToAction("Index");
        }

        var oldRoles = userService.GetRoles(model.Id).ToArray();
        var newRoles = model.SelectedRoleNames;

        user.IsActive = model.IsActive;
        user.UserName = user.UserName;
        user.Email = model.Email;
        user.EmailConfirmed = model.EmailConfirmed;
        user.Description = model.Description;
        user.PictureId = model.AvatarId;
        user.Name = model.Name;
        user.Surname = model.Surname;
        user.Location = model.Location;
        user.Badge = model.Badge;
        user.NormalizedUserName = user.UserName;
        user.ControlID = model.ControlID;


        if (Request.IsAuthenticated && (User.IsInRole("BF Administrator")))
        {
          newRoles = model.SelectedRoleNames;
        }
        else
        {
          newRoles = oldRoles;

          user.IsActive = user.IsActive;
          user.UserName = user.UserName;
          user.Email = model.Email;
          user.EmailConfirmed = model.EmailConfirmed;
          user.Description = model.Description;
          user.PictureId = model.AvatarId;
          user.Name = user.Name;
          user.Surname = user.Surname;
          user.Location = user.Location;
          user.Badge = model.Badge;
          user.NormalizedUserName = user.UserName;
          user.ControlID = model.ControlID;

        }


        #region AddOrRemoveRoles
        try
        {
          var rolesToRemove = oldRoles.Except(newRoles);
          foreach (var role in rolesToRemove)
            userService.RemoveFromRole(user.Id, role);

          var rolesToAdd = newRoles.Except(oldRoles);
          foreach (var role in rolesToAdd)
            userService.AddToRole(user.Id, role);
        }
        catch
        {

        }
        #endregion AddOrRemoveRoles

        var result = userService.Update(user);
        if (result.Succeeded)
          this.NotifySuccess("Successfully saved.");
        else
          this.NotifyError("User can not saved!");

        return RedirectToAction("Edit", new { id = model.Id });
      }

      return View(model);
    }

