    // File Upload
    //===============================================================
    [Authorize(Roles = "BF User Add Image,BF User Manager (Training)")]
    [HttpPost]
    public ActionResult UploadFile()
    {
      string name = "";
      // Checking no of files injected in Request object  

      int test = Request.Files.Count;
      if (Request.Files.Count > 0)
      {
        try
        {
          //  Get all files from Request object  
          HttpPostedFileBase fileBase = Request.Files["file_name"];
          HttpFileCollectionBase files = Request.Files;
          string resultado = "";
          for (int i = 0; i < files.Count; i++)
          {
            //string path = AppDomain.CurrentDomain.BaseDirectory + "Uploads/";
            string filename = Path.GetFileName(Request.Files[i].FileName);
            HttpPostedFileBase file = files[i];
            string fname;
            string fext;

            // Checking for Internet Explorer  
            if (Request.Browser.Browser.ToUpper() == "IE" || Request.Browser.Browser.ToUpper() == "INTERNETEXPLORER")
            {
              string[] testfiles = file.FileName.Split(new char[] { '\\' });
              fname = testfiles[testfiles.Length - 1];
            }
            else
            {
              fname = file.FileName;
            }
            fext = Path.GetExtension(fname);


            if (Firstronic.Framework.Upload.Upload.IsValidExtension(fext) && Firstronic.Framework.Upload.Upload.IsValidName(fname))
            {

              int id = 0;

              try
              {
                id = Firstronic.Framework.Functions.Queries.GetNextIDFromQuery("Common_Files_Uploaded", "FileID");
              }
              catch (Exception ex)
              {
                ViewBag.Message = "ERROR:" + ex.Message.ToString();
              }
              name = id + "_" + 0 + fext;
              SqlParameter[] parameters = new SqlParameter[]{
                        new SqlParameter("@FileName",SqlDbType.NVarChar){Value = name},
                        new SqlParameter("@Extension",SqlDbType.NVarChar){Value = fext},
                };

              //var result = db.ExecuteInsertCommand($@"", parameters);

              var result_Update = db.ExecuteInsertCommand(@"INSERT INTO Common_Files_Uploaded  ([FileName],Extension) VALUES (@FileName,@Extension)", parameters);
              // Get the complete folder path and store the file inside it.  
              fname = Path.Combine(Server.MapPath("~/UploadedFiles/Users"), name);
              file.SaveAs(fname);

              resultado = name;


            }

          }
          // Returns message that successfully uploaded  
          return Json(resultado);
        }
        catch (Exception ex)
        {
          ViewBag.Message = "ERROR:" + ex.Message.ToString();
          return Json("");
        }
      }
      else
      {
        return Json("");
      }
    }

