@using Firstronic.Areas.Manage.Controllers
@model tbl_Common_Building

@{
    bool isNew = !(Model != null && Model.Building_Key.HasValue && Model.Building_Key.Value > 0);
}

@using (Html.BeginForm())
{
    @Html.AntiForgeryToken()
    @Html.ValidationSummary("", new { @class = "hide" })

    <div class="md-card">
        <div class="md-card-toolbar">
            <h3 class="md-card-toolbar-heading-text">Manage Building: @(isNew ? "Create New" : Model.Name)</h3>
        </div>
        <div class="md-card-content">

            @Html.HiddenFor(x => x.Building_Key)

            <ul class="uk-tab uk-tab-grid" data-uk-tab="{connect:'#tabs_building'}">
                <li class="uk-width-1-2 uk-active"><a href="#">General</a></li>
                <li class="uk-width-1-2"><a href="#">Settings</a></li>
            </ul>

            <ul id="tabs_building" class="uk-switcher uk-margin">
                <li aria-hidden="false" class="uk-active">

                    <div class="uk-grid">
                        <div class="uk-width-1-1">
                            <p class="request-info">General Information</p>
                        </div>
                        <div class="uk-width-1-3@s">
                            @Html.LabelFor(x => x.Building_Key, new { @class = "m-0 fs-14" })
                            @Html.TextBoxFor(x => x.Building_Key, new { @class = "md-input" })
                        </div>
                        <div class="uk-width-1-3@s">
                            @Html.LabelFor(x => x.Building_Code, new { @class = "m-0 fs-14" })
                            @Html.TextBoxFor(x => x.Building_Code, new { @class = "md-input" })
                        </div>
                        <div class="uk-width-1-3@s">
                            @Html.LabelFor(x => x.Name, new { @class = "m-0 fs-14" })
                            @Html.TextBoxFor(x => x.Name, new { @class = "md-input" })
                        </div>
                        <div class="uk-width-1-3@s">
                            @Html.LabelFor(x => x.Facility_Key, new { @class = "m-0 fs-14" })
                            @Html.DropDownListFor(x => x.Facility_Key, Model.FacilityList, "-- Select Facility --", new { @class = "md-input" })
                        </div>
                        <div class="uk-width-1-3@s">
                            @Html.LabelFor(x => x.Default_Location, new { @class = "m-0 fs-14" })
                            @Html.TextBoxFor(x => x.Default_Location, new { @class = "md-input" })
                        </div>
                        <div class="uk-width-1-3@s">
                            @Html.LabelFor(x => x.Receiving_Location, new { @class = "m-0 fs-14" })
                            @Html.TextBoxFor(x => x.Receiving_Location, new { @class = "md-input" })
                        </div>
                        <div class="uk-width-1-3@s">
                            @Html.LabelFor(x => x.Shipping_Location, new { @class = "m-0 fs-14" })
                            @Html.TextBoxFor(x => x.Shipping_Location, new { @class = "md-input" })
                        </div>
                        <div class="uk-width-1-3@s">
                            @Html.LabelFor(x => x.Width, new { @class = "m-0 fs-14" })
                            @Html.TextBoxFor(x => x.Width, new { @class = "md-input", @type = "number" })
                        </div>
                        <div class="uk-width-1-3@s">
                            @Html.LabelFor(x => x.Height, new { @class = "m-0 fs-14" })
                            @Html.TextBoxFor(x => x.Height, new { @class = "md-input", @type = "number" })
                        </div>
                    </div>

                </li>

                <li aria-hidden="true">

                    <div class="uk-grid">
                        <div class="uk-width-1-1">
                            <p class="request-info">Facility Types</p>
                        </div>
                        <div class="uk-width-1-2@s">
                            @Html.CheckBoxFor(x => x.Main_Facility, new { @class = "icheckbox_md" })
                            @Html.LabelFor(x => x.Main_Facility, new { @class = "m-0 fs-14" })
                        </div>
                        <div class="uk-width-1-2@s">
                            @Html.CheckBoxFor(x => x.PRODUCTION, new { @class = "icheckbox_md" })
                            @Html.LabelFor(x => x.PRODUCTION, new { @class = "m-0 fs-14" })
                        </div>
                        <div class="uk-width-1-2@s">
                            @Html.CheckBoxFor(x => x.WAREHOUSE, new { @class = "icheckbox_md" })
                            @Html.LabelFor(x => x.WAREHOUSE, new { @class = "m-0 fs-14" })
                        </div>
                        <div class="uk-width-1-2@s">
                            @Html.CheckBoxFor(x => x.SHIPPING, new { @class = "icheckbox_md" })
                            @Html.LabelFor(x => x.SHIPPING, new { @class = "m-0 fs-14" })
                        </div>
                    </div>

                </li>
            </ul>

            <div class="uk-clearfix md-card-overlay-header mn-t-25">
                <a class="md-btn md-btn-primary md-btn-small" href="@Url.Action("Index", "Building")">
                    <i class="fa fa-arrow-left mr-1 fs-12"></i> Back
                </a>

                <button type="submit" name="action:@(isNew ? "Create": "Edit")" class="md-btn md-btn-primary md-btn-small">
                    <i class="fa fa-save mr-1 fs-14"></i> Save
                </button>

                @if (!isNew)
                {
                    @(Html.Fst().ConfirmModal("Delete", "Building", new { @id = Model.Building_Key })
                                                                         .Title("Confirm Delete")
                                                                         .Content("Are you sure do you want to delete this building?")
                                                                         .For(Html.Fst().Button().Text("Delete").Color(BootstrapColor.Danger).Size(ButtonSize.Small).Icon("fa fa-trash mr-1 fs-14"))
                    )
                }
            </div>

        </div>
    </div>
}

